from typing import List, Dict, Any
from leann.api import PassageManager, LeannSearcher
from pathlib import Path
import json
from collections import Counter, defaultdict

def _resolve_passages_file(index_path: Path, meta: Dict[str, Any]) -> Path:
    """Helper to resolve the path to the passages file."""
    # 1. Try path specified in metadata
    if "passages_path" in meta:
        # Paths in metadata are typically relative to the metadata file
        candidate = index_path.parent / meta["passages_path"]
        if candidate.exists():
            return candidate

    # 2. Try <index_name>.jsonl
    candidate = index_path.parent / f"{index_path.name}.jsonl"
    if candidate.exists():
        return candidate

    # 3. Try <index_name>.passages.jsonl
    candidate = index_path.parent / f"{index_path.name}.passages.jsonl"
    if candidate.exists():
        return candidate

    # 4. Try replacing extension with .jsonl (e.g. index.leann -> index.jsonl)
    if index_path.suffix:
        candidate = index_path.with_suffix(".jsonl")
        if candidate.exists():
            return candidate

    raise FileNotFoundError(f"Could not locate passages file for index {index_path}")

def get_index_statistics(
    index_path: str
) -> Dict[str, Any]:
    """Get comprehensive statistics about a LEANN index.

Args:
    index_path: Path to the LEANN index file

Returns:
    Dictionary containing:
    {
        "total_passages": total number of passages,
        "metadata_fields": list of unique metadata field names,
        "field_value_counts": dictionary of field value counts
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""
    path = Path(index_path)
    # Based on leann/searcher_base.py logic
    meta_path = path.parent / f"{path.name}.meta.json"

    if not meta_path.exists():
        raise FileNotFoundError(f"Index metadata file not found: {meta_path}")

    with open(meta_path, "r", encoding="utf-8") as f:
        meta = json.load(f)

    passages_file = _resolve_passages_file(path, meta)

    total_passages = 0
    field_value_counts = defaultdict(Counter)

    with open(passages_file, "r", encoding="utf-8") as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            try:
                doc = json.loads(line)
                total_passages += 1

                # Expecting {"text": ..., "metadata": {...}}
                metadata = doc.get("metadata", {})
                if not isinstance(metadata, dict):
                    continue

                for k, v in metadata.items():
                    # Convert unhashable types to string representation for counting
                    if isinstance(v, (dict, list)):
                        v = str(v)
                    field_value_counts[k][v] += 1

            except json.JSONDecodeError:
                continue

    return {
        "total_passages": total_passages,
        "metadata_fields": list(field_value_counts.keys()),
        "field_value_counts": {k: dict(v) for k, v in field_value_counts.items()}
    }

def analyze_index_coverage(index_path: str, required_fields: List[str]) -> Dict[str, Any]:
    """Analyze how well an index covers required metadata fields.

Args:
    index_path: Path to the LEANN index file
    required_fields: List of metadata field names that should be present

Returns:
    Dictionary containing:
    {
        "coverage_percentage": percentage of passages that have all required fields,
        "field_coverage": dictionary mapping field name to coverage percentage,
        "missing_fields": list of required fields not found in any passage
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""
    path = Path(index_path)
    meta_path = path.parent / f"{path.name}.meta.json"

    if not meta_path.exists():
        raise FileNotFoundError(f"Index metadata file not found: {meta_path}")

    with open(meta_path, "r", encoding="utf-8") as f:
        meta = json.load(f)

    passages_file = _resolve_passages_file(path, meta)

    total_passages = 0
    passages_with_all = 0
    field_presence_counts = Counter()

    with open(passages_file, "r", encoding="utf-8") as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            try:
                doc = json.loads(line)
                total_passages += 1

                metadata = doc.get("metadata", {})
                if not isinstance(metadata, dict):
                    metadata = {}

                has_all = True
                for field in required_fields:
                    if field in metadata:
                        field_presence_counts[field] += 1
                    else:
                        has_all = False

                if has_all:
                    passages_with_all += 1

            except json.JSONDecodeError:
                continue

    if total_passages == 0:
        coverage_percentage = 0.0
        field_coverage = {field: 0.0 for field in required_fields}
    else:
        coverage_percentage = (passages_with_all / total_passages) * 100.0
        field_coverage = {
            field: (field_presence_counts[field] / total_passages) * 100.0
            for field in required_fields
        }

    missing_fields = [
        field for field in required_fields 
        if field_presence_counts[field] == 0
    ]

    return {
        "coverage_percentage": coverage_percentage,
        "field_coverage": field_coverage,
        "missing_fields": missing_fields
    }
