from leann.api import PassageManager
from pathlib import Path
import json

def get_passages_by_metadata_list(
    index_path: str,
    field_name: str,
    allowed_values: List[Any]
) -> List[Dict[str, Any]]:
    """Retrieve passages from an index where a metadata field matches any value in a list.

Args:
    index_path: Path to the LEANN index file
    field_name: Metadata field name to filter by
    allowed_values: List of field values to match (passages matching any value will be returned)

Returns:
    List of passage dictionaries that have the field matching any value in allowed_values

Raises:
    FileNotFoundError: If index metadata file is not found
    ValueError: If allowed_values is empty"""

    if not allowed_values:
        raise ValueError("allowed_values cannot be empty")

    if not Path(index_path).exists():
        raise FileNotFoundError(f"Index metadata file not found: {index_path}")

    pm = PassageManager(index_path)

    results = []

    # Attempt to create a set for O(1) lookups
    try:
        allowed_set = set(allowed_values)
    except TypeError:
        allowed_set = None

    # Iterate over all passage files registered in the index
    # pm.offset_maps keys are the file paths containing passages
    for passage_file in pm.offset_maps:
        try:
            with open(passage_file, 'r', encoding='utf-8') as f:
                for line in f:
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        passage = json.loads(line)

                        # Check if the metadata field exists in the passage
                        if field_name in passage:
                            value = passage[field_name]
                            is_match = False

                            if allowed_set is not None:
                                try:
                                    if value in allowed_set:
                                        is_match = True
                                except TypeError:
                                    # Fallback for unhashable values (e.g. lists)
                                    if value in allowed_values:
                                        is_match = True
                            else:
                                if value in allowed_values:
                                    is_match = True

                            if is_match:
                                results.append(passage)
                    except json.JSONDecodeError:
                        continue
        except FileNotFoundError:
            continue

    return results
